input.content:
"""Generate the CI ``variants`` job from a declarative target manifest.

The manifest (``.github/ci-targets.toml``) is the single source of truth for
which mise variants CI supports, which runner each runs on, and which CI steps
each variant runs. This module regenerates the matrix and step regions of
``.github/workflows/ci.yml`` (delimited by sentinel markers) and validates that
the checked-in workflow, the manifest, and the ``.mise/config.<variant>.toml``
files all agree.

Usage:
    uv run python scripts/ci_matrix.py generate   # rewrite ci.yml in place
    uv run python scripts/ci_matrix.py check       # exit 1 on drift
    uv run python scripts/ci_matrix.py matrix      # print the matrix as JSON
"""

from __future__ import annotations

import argparse
import json
import re
import sys
import tomllib
from collections.abc import Iterable, Sequence
from dataclasses import dataclass
from pathlib import Path

try:
    import yaml
except ImportError:  # pragma: no cover - PyYAML is a dev dependency in CI.
    yaml = None

ROOT = Path(__file__).resolve().parents[1]
MANIFEST_PATH = ROOT / ".github" / "ci-targets.toml"
WORKFLOW_PATH = ROOT / ".github" / "workflows" / "ci.yml"
CONFIG_DIR = ROOT / ".mise"

# Sentinels bracketing generated regions in ci.yml. `generate` rewrites the
# text between each pair; `check` parses the file semantically instead.
MATRIX_BEGIN = "          # @generate matrix begin"
MATRIX_END = "          # @generate matrix end"
STEPS_BEGIN = "      # @generate steps begin"
STEPS_END = "      # @generate steps end"

# Exactly one of these must be enabled per target (build-only vs build+test).
NATIVE_STEPS = frozenset({"build_native", "test_native"})

# Indentation of the matrix `include` entries and the job `steps` in ci.yml.
_MATRIX_ITEM_INDENT = "          "
_MATRIX_FIELD_INDENT = "            "
_STEP_INDENT = "      "
_STEP_FIELD_INDENT = "        "


class ConfigError(Exception):
    """Raised when the manifest, config files, or workflow are out of sync."""


@dataclass(frozen=True)
class Step:
    key: str
    name: str
    run: str
    comment: tuple[str, ...] = ()


@dataclass(frozen=True)
class Target:
    variant: str
    runner: str
    steps: frozenset[str]


@dataclass(frozen=True)
class Manifest:
    steps: tuple[Step, ...]
    targets: tuple[Target, ...]

    @property
    def step_keys(self) -> tuple[str, ...]:
        return tuple(step.key for step in self.steps)

    def step(self, key: str) -> Step:
        for step in self.steps:
            if step.key == key:
                return step
        raise ConfigError(f"unknown step key: {key!r}")


# --------------------------------------------------------------------------- #
# Manifest loading and validation
# --------------------------------------------------------------------------- #


def _as_str(value: object, field: str, context: str) -> str:
    if not isinstance(value, str) or not value.strip():
        raise ConfigError(f"{context}: {field} must be a non-empty string")
    return value


def _as_str_list(value: object, field: str, context: str) -> list[str]:
    if not isinstance(value, list) or not all(isinstance(v, str) for v in value):
        raise ConfigError(f"{context}: {field} must be an array of strings")
    return value


def parse_manifest(data: dict[str, object]) -> Manifest:
    """Validate raw parsed TOML and build a :class:`Manifest`.

    Pure function: takes the already-parsed mapping so it is trivially testable.
    """
    raw_steps = data.get("step")
    if not isinstance(raw_steps, list) or not raw_steps:
        raise ConfigError("manifest must define at least one [[step]]")

    steps: list[Step] = []
    seen_steps: set[str] = set()
    for index, raw in enumerate(raw_steps):
        if not isinstance(raw, dict):
            raise ConfigError(f"step[{index}] must be a table")
        ctx = f"step[{index}]"
        key = _as_str(raw.get("key"), "key", ctx)
        if key in seen_steps:
            raise ConfigError(f"{ctx}: duplicate step key {key!r}")
        seen_steps.add(key)
        name = _as_str(raw.get("name"), "name", ctx)
        run = _as_str(raw.get("run"), "run", ctx)
        comment: tuple[str, ...] = ()
        if "comment" in raw:
            comment = tuple(_as_str_list(raw["comment"], "comment", ctx))
        steps.append(Step(key=key, name=name, run=run, comment=comment))

    step_keys = seen_steps
    native = step_keys & NATIVE_STEPS
    if not native:
        raise ConfigError(
            "manifest must define both 'build_native' and 'test_native' steps"
        )
    if native != NATIVE_STEPS:
        missing = NATIVE_STEPS - native
        raise ConfigError(f"manifest is missing native step(s): {sorted(missing)}")

    raw_targets = data.get("target")
    if not isinstance(raw_targets, list) or not raw_targets:
        raise ConfigError("manifest must define at least one [[target]]")

    targets: list[Target] = []
    seen_variants: set[str] = set()
    for index, raw in enumerate(raw_targets):
        if not isinstance(raw, dict):
            raise ConfigError(f"target[{index}] must be a table")
        ctx = f"target[{index}]"
        variant = _as_str(raw.get("variant"), "variant", ctx)
        if variant in seen_variants:
            raise ConfigError(f"{ctx}: duplicate variant {variant!r}")
        seen_variants.add(variant)
        runner = _as_str(raw.get("runner"), "runner", ctx)
        step_list = _as_str_list(raw.get("steps"), "steps", ctx)
        target_steps = set(step_list)
        unknown = target_steps - step_keys
        if unknown:
            raise ConfigError(
                f"{ctx} ({variant}): unknown step(s): {sorted(unknown)}"
            )
        chosen_native = target_steps & NATIVE_STEPS
        if len(chosen_native) != 1:
            raise ConfigError(
                f"{ctx} ({variant}): must run exactly one of "
                f"{sorted(NATIVE_STEPS)}, got {sorted(chosen_native) or 'none'}"
            )
        targets.append(
            Target(variant=variant, runner=runner, steps=frozenset(target_steps))
        )

    return Manifest(steps=tuple(steps), targets=tuple(targets))


def load_manifest(path: Path = MANIFEST_PATH) -> Manifest:
    if not path.is_file():
        raise ConfigError(f"manifest not found: {path}")
    with path.open("rb") as handle:
        data = tomllib.load(handle)
    return parse_manifest(data)


# --------------------------------------------------------------------------- #
# Config-file synchronization
# --------------------------------------------------------------------------- #


def list_config_variants(config_dir: Path = CONFIG_DIR) -> set[str]:
    """Variants declared via ``.mise/config.<variant>.toml`` files."""
    prefix = "config."
    suffix = ".toml"
    variants: set[str] = set()
    for entry in sorted(config_dir.glob(f"{prefix}*{suffix}")):
        name = entry.name
        if not name.startswith(prefix) or not name.endswith(suffix):
            continue
        variants.add(name[len(prefix) : len(name) - len(suffix)])
    return variants


def validate_config_sync(
    manifest: Manifest, config_dir: Path = CONFIG_DIR
) -> None:
    """Every manifest target needs a config file, and vice versa."""
    config_variants = list_config_variants(config_dir)
    targets = {target.variant for target in manifest.targets}

    missing_configs = targets - config_variants
    if missing_configs:
        raise ConfigError(
            "manifest target(s) without a .mise/config.<variant>.toml: "
            + ", ".join(sorted(missing_configs))
        )
    orphan_configs = config_variants - targets
    if orphan_configs:
        raise ConfigError(
            ".mise/config.<variant>.toml without a manifest target: "
            + ", ".join(sorted(orphan_configs))
        )


# --------------------------------------------------------------------------- #
# Matrix + step rendering
# --------------------------------------------------------------------------- #


def matrix_entries(manifest: Manifest) -> list[dict[str, object]]:
    """One matrix entry per target, with a boolean column for every step."""
    entries: list[dict[str, object]] = []
    for target in manifest.targets:
        entry: dict[str, object] = {
            "mise_env": target.variant,
            "runner": target.runner,
        }
        for step in manifest.steps:
            entry[step.key] = step.key in target.steps
        entries.append(entry)
    return entries


def render_matrix(manifest: Manifest) -> str:
    lines: list[str] = []
    for target in manifest.targets:
        lines.append(f"{_MATRIX_ITEM_INDENT}- mise_env: {target.variant}")
        lines.append(f"{_MATRIX_FIELD_INDENT}runner: {target.runner}")
        for step in manifest.steps:
            value = "true" if step.key in target.steps else "false"
            lines.append(f"{_MATRIX_FIELD_INDENT}{step.key}: {value}")
    return "\n".join(lines) + "\n"


def _if_expression(key: str) -> str:
    return "${{ matrix." + key + " }}"


def render_steps(manifest: Manifest) -> str:
    lines: list[str] = []
    for step in manifest.steps:
        for line in step.comment:
            lines.append(f"{_STEP_INDENT}# {line}")
        lines.append(f"{_STEP_INDENT}- name: {step.name}")
        lines.append(f"{_STEP_FIELD_INDENT}if: ${{{{ matrix.{step.key} }}}}")
        lines.append(f"{_STEP_FIELD_INDENT}run: {step.run}")
    return "\n".join(lines) + "\n"


def _replace_region(text: str, begin: str, end: str, content: str) -> str:
    pattern = re.compile(
        re.escape(begin) + r"\n(.*?)" + re.escape(end), re.DOTALL
    )
    new_text, count = pattern.subn(begin + "\n" + content + end, text, count=1)
    if count != 1:
        raise ConfigError(f"sentinel marker not found exactly once: {begin!r}")
    return new_text


def regenerate(text: str, manifest: Manifest) -> str:
    """Rewrite both generated regions of ``ci.yml`` from the manifest."""
    text = _replace_region(text, MATRIX_BEGIN, MATRIX_END, render_matrix(manifest))
    text = _replace_region(text, STEPS_BEGIN, STEPS_END, render_steps(manifest))
    return text


# --------------------------------------------------------------------------- #
# Semantic drift check (formatting-independent)
# --------------------------------------------------------------------------- #

_IF_RE = re.compile(r"^\$\{\{\s*matrix\.([A-Za-z0-9_]+)\s*\}\}$")


def check_workflow(text: str, manifest: Manifest) -> None:
    """Validate a workflow's variants job matches the manifest semantically.

    Unlike :func:`regenerate`, this parses the YAML, so cosmetic reformatting by
    dprint or editors never produces a false drift report.
    """
    if yaml is None:
        raise ConfigError("PyYAML is required to check the workflow")
    try:
        doc = yaml.safe_load(text)
    except yaml.YAMLError as exc:  # pragma: no cover - defensive
        raise ConfigError(f"ci.yml is not valid YAML: {exc}") from exc

    if not isinstance(doc, dict):
        raise ConfigError("ci.yml has no top-level mapping")
    jobs = doc.get("jobs")
    if not isinstance(jobs, dict) or "variants" not in jobs:
        raise ConfigError("ci.yml is missing the 'variants' job")
    variants = jobs["variants"]

    matrix = _expect_mapping(
        _expect_mapping(variants, "variants")("strategy", "variants"), "strategy"
    )("matrix", "strategy")
    include = matrix.get("include")
    if not isinstance(include, list) or not include:
        raise ConfigError("variants job has no matrix.include")

    actual = {
        entry["mise_env"]: entry
        for entry in include
        if isinstance(entry, dict) and "mise_env" in entry
    }
    expected = {entry["mise_env"]: entry for entry in matrix_entries(manifest)}

    if set(actual) != set(expected):
        only_manifest = sorted(set(expected) - set(actual))
        only_workflow = sorted(set(actual) - set(expected))
        details = []
        if only_manifest:
            details.append(f"missing from workflow: {only_manifest}")
        if only_workflow:
            details.append(f"missing from manifest: {only_workflow}")
        raise ConfigError("matrix variants drifted: " + "; ".join(details))

    for mise_env, expected_entry in expected.items():
        actual_entry = actual[mise_env]
        if actual_entry != expected_entry:
            diff = _diff_entry(expected_entry, actual_entry)
            raise ConfigError(
                f"matrix entry for {mise_env!r} drifted: {diff}"
            )

    workflow_steps = _matrix_gated_steps(variants.get("steps", []))
    expected_steps = {step.key: (step.name, step.run) for step in manifest.steps}

    missing = sorted(set(expected_steps) - set(workflow_steps))
    if missing:
        raise ConfigError(
            f"matrix-gated step(s) missing from workflow: {missing}"
        )
    extra = sorted(set(workflow_steps) - set(expected_steps))
    if extra:
        raise ConfigError(
            f"workflow has matrix-gated step(s) absent from manifest: {extra}"
        )
    for key, (name, run) in expected_steps.items():
        if workflow_steps[key] != (name, run):
            raise ConfigError(
                f"step {key!r} name/run drifted: "
                f"manifest={(name, run)!r} workflow={workflow_steps[key]!r}"
            )


def _expect_mapping(value: object, label: str):
    def lookup(key: str, ctx: str):
        if not isinstance(value, dict):
            raise ConfigError(f"ci.yml '{ctx}' is not a mapping")
        if key not in value:
            raise ConfigError(f"ci.yml '{ctx}' is missing '{key}'")
        return value[key]

    lookup.label = label  # type: ignore[attr-defined]
    return lookup


def _matrix_gated_steps(steps: Iterable[object]) -> dict[str, tuple[str, str]]:
    result: dict[str, tuple[str, str]] = {}
    for raw in steps:
        if not isinstance(raw, dict) or "if" not in raw:
            continue
        match = _IF_RE.match(str(raw["if"]).strip())
        if not match:
            continue
        key = match.group(1)
        result[key] = (str(raw.get("name", "")), str(raw.get("run", "")))
    return result


def _diff_entry(expected: dict[str, object], actual: dict[str, object]) -> str:
    changes: list[str] = []
    for key, value in expected.items():
        if actual.get(key) != value:
            changes.append(
                f"{key}: manifest={value!r} workflow={actual.get(key)!r}"
            )
    extra = sorted(set(actual) - set(expected))
    for key in extra:
        changes.append(f"{key}: unexpected in workflow={actual[key]!r}")
    return "; ".join(changes)


# --------------------------------------------------------------------------- #
# CLI
# --------------------------------------------------------------------------- #


def _paths(args: argparse.Namespace) -> tuple[Path, Path, Path]:
    root = Path(args.root) if args.root else ROOT
    manifest = Path(args.manifest) if args.manifest else root / ".github" / "ci-targets.toml"
    workflow = Path(args.workflow) if args.workflow else root / ".github" / "workflows" / "ci.yml"
    config_dir = Path(args.config_dir) if args.config_dir else root / ".mise"
    return manifest, workflow, config_dir


def _cmd_generate(args: argparse.Namespace) -> int:
    manifest_path, workflow_path, config_dir = _paths(args)
    manifest = load_manifest(manifest_path)
    validate_config_sync(manifest, config_dir)
    text = workflow_path.read_text(encoding="utf-8")
    new_text = regenerate(text, manifest)
    if new_text != text:
        workflow_path.write_text(new_text, encoding="utf-8")
        print(f"updated {workflow_path.relative_to(_root_of(workflow_path, manifest_path))}")
    else:
        print("already up to date")
    return 0


def _root_of(workflow: Path, manifest: Path) -> Path:
    # Resolve the repo root from the manifest path (.github/<manifest>).
    return manifest.resolve().parents[1]


def _cmd_check(args: argparse.Namespace) -> int:
    manifest_path, workflow_path, config_dir = _paths(args)
    manifest = load_manifest(manifest_path)
    validate_config_sync(manifest, config_dir)
    text = workflow_path.read_text(encoding="utf-8")
    check_workflow(text, manifest)
    print("ci.yml is in sync with ci-targets.toml")
    return 0


def _cmd_matrix(args: argparse.Namespace) -> int:
    manifest_path, _, config_dir = _paths(args)
    manifest = load_manifest(manifest_path)
    validate_config_sync(manifest, config_dir)
    json.dump(matrix_entries(manifest), sys.stdout, indent=2)
    sys.stdout.write("\n")
    return 0


def main(argv: Sequence[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        prog="ci_matrix",
        description="Generate and validate the CI variants workflow from a manifest.",
    )
    parser.add_argument(
        "--root", help="repository root (defaults to this script's parent)"
    )
    parser.add_argument("--manifest", help="override manifest path")
    parser.add_argument("--workflow", help="override ci.yml path")
    parser.add_argument("--config-dir", help="override .mise config directory")
    sub = parser.add_subparsers(dest="command", required=True)
    sub.add_parser("generate", help="rewrite ci.yml from the manifest")
    sub.add_parser("check", help="exit non-zero if ci.yml drifted")
    sub.add_parser("matrix", help="print the matrix as JSON")
    args = parser.parse_args(argv)

    try:
        if args.command == "generate":
            return _cmd_generate(args)
        if args.command == "check":
            return _cmd_check(args)
        if args.command == "matrix":
            return _cmd_matrix(args)
    except ConfigError as exc:
        print(f"error: {exc}", file=sys.stderr)
        return 1
    parser.error(f"unknown command: {args.command}")  # pragma: no cover
    return 2  # pragma: no cover


if __name__ == "__main__":
    raise SystemExit(main())

