_ENTRY_ITEM_RE = re.compile(r"^ *- mise_env: (.+?)\s*$")
_FIELD_RE = re.compile(r"^ *([A-Za-z0-9_]+): (.+?)\s*$")
_STEP_NAME_RE = re.compile(r"^ *- name: (.+?)\s*$")
_STEP_IF_RE = re.compile(r"^\$\{\{\s*matrix\.([A-Za-z0-9_]+)\s*\}\}$")


def _extract_region(text: str, begin: str, end: str) -> str:
    pattern = re.compile(re.escape(begin) + r"\n(.*?)" + re.escape(end), re.DOTALL)
    match = pattern.search(text)
    if match is None:
        raise ConfigError(f"sentinel marker not found: {begin!r}")
    if pattern.search(text, match.end()) is not None:
        raise ConfigError(f"sentinel marker found more than once: {begin!r}")
    return match.group(1)


def _parse_scalar(value: str) -> str | bool:
    if value == "true":
        return True
    if value == "false":
        return False
    return value


def _parse_matrix_region(text: str) -> list[dict[str, object]]:
    entries: list[dict[str, object]] = []
    current: dict[str, object] | None = None
    for raw_line in text.splitlines():
        line = raw_line.rstrip()
        if not line.strip() or line.lstrip().startswith("#"):
            continue
        item = _ENTRY_ITEM_RE.match(line)
        if item:
            if current is not None:
                entries.append(current)
            current = {"mise_env": item.group(1).strip()}
            continue
        field = _FIELD_RE.match(line)
        if field and current is not None:
            current[field.group(1)] = _parse_scalar(field.group(2).strip())
    if current is not None:
        entries.append(current)
    return entries


def _parse_steps_region(text: str) -> dict[str, tuple[str, str]]:
    steps: dict[str, tuple[str, str]] = []
    pending: dict[str, object] | None = None

    def flush() -> None:
        nonlocal pending
        if pending and pending.get("if_key") is not None:
            steps.append(
                (
                    str(pending["if_key"]),
                    (str(pending["name"]), str(pending.get("run", ""))),
                )
            )
        pending = None

    for raw_line in text.splitlines():
        line = raw_line.rstrip()
        if not line.strip() or line.lstrip().startswith("#"):
            continue
        name = _STEP_NAME_RE.match(line)
        if name:
            flush()
            pending = {"name": name.group(1).strip()}
            continue
        field = _FIELD_RE.match(line)
        if field and pending is not None:
            key, value = field.group(1), field.group(2).strip()
            if key == "if":
                if_match = _STEP_IF_RE.match(value)
                if if_match:
                    pending["if_key"] = if_match.group(1)
            elif key == "run":
                pending["run"] = value
    flush()
    return dict(steps)


